import math
from itertools import permutations
class Solution:
    def numSquarefulPerms(self, nums):
        def sq(x):
            r = int(math.isqrt(x))
            return r * r == x
        seen = set()
        count = 0
        for p in set(permutations(nums)):
            if all(sq(p[i] + p[i + 1]) for i in range(len(p) - 1)):
                count += 1
        return count

