import math
class Solution:
    def numSquarefulPerms(self, nums):
        nums.sort()
        n = len(nums)
        used = [False] * n
        def sq(x):
            r = math.isqrt(x)
            return r * r == x
        self.cnt = 0
        def bt(prev, depth):
            if depth == n:
                self.cnt += 1
                return
            for i in range(n):
                if used[i]:
                    continue
                if i > 0 and nums[i] == nums[i - 1] and not used[i - 1]:
                    continue
                if prev is not None and not sq(prev + nums[i]):
                    continue
                used[i] = True
                bt(nums[i], depth + 1)
                used[i] = False
        bt(None, 0)
        return self.cnt

