var numSquarefulPerms = function(nums) {
    nums.sort((a, b) => a - b);
    const n = nums.length;
    const used = new Array(n).fill(false);
    const sq = (x) => { const r = Math.floor(Math.sqrt(x)); return r * r === x || (r + 1) * (r + 1) === x; };
    let cnt = 0;
    const bt = (prev, depth) => {
        if (depth === n) { cnt++; return; }
        for (let i = 0; i < n; i++) {
            if (used[i]) continue;
            if (i > 0 && nums[i] === nums[i - 1] && !used[i - 1]) continue;
            if (prev !== null && !sq(prev + nums[i])) continue;
            used[i] = true;
            bt(nums[i], depth + 1);
            used[i] = false;
        }
    };
    bt(null, 0);
    return cnt;
};
